select competencia,evento,categoria,sexo,clavadista,total,juez1,juez2,juez3,juez4,juez5,juez6,juez7,sum(puntaje_1) AS p1,sum(puntaje_2) AS p2,sum(puntaje_3) AS p3,sum(puntaje_4) AS p4,sum(puntaje_5) AS p5,sum(puntaje_6) AS p6,sum(puntaje_7) AS p7 
FROM puntajes_jueces_0 
group by competencia,evento,categoria,sexo,clavadista 
order by categoria,sexo,total desc;

select competencia,evento,categoria,sexo,clavadista,total,ronda,salto,posicion,altura,grado_dif, penalizado,total_salto,puntaje_salto,juez1,juez2,juez3,juez4,juez5,juez6,juez7,cal1,cal2,cal3,cal4,cal5,cal6,cal7,if(d.cal1 is not null,if(d.penalizado is not null,(d.cal1 - d.penalizado) * 3 * d.grado_dif,d.cal1 * 3 * d.grado_dif),NULL) AS puntaje_1,if(d.cal2 is not null,if(d.penalizado is not null,(d.cal2 - d.penalizado) * 3 * d.grado_dif,d.cal2 * 3 * d.grado_dif),NULL) AS puntaje_2,if(d.cal3 is not null,if(d.penalizado is not null,(d.cal3 - d.penalizado) * 3 * d.grado_dif,d.cal3 * 3 * d.grado_dif),NULL) AS puntaje_3,if(d.cal4 is not null,if(d.penalizado is not null,(d.cal4 - d.penalizado) * 3 * d.grado_dif,d.cal4 * 3 * d.grado_dif),NULL) AS puntaje_4,if(d.cal5 is not null,if(d.penalizado is not null,(d.cal5 - d.penalizado) * 3 * d.grado_dif,d.cal5 * 3 * d.grado_dif),NULL) AS puntaje_5,if(d.cal6 is not null,if(d.penalizado is not null,(d.cal6 - d.penalizado) * 3 * d.grado_dif,d.cal6 * 3 * d.grado_dif),NULL) AS puntaje_6,if(`d`.`cal7` is not null,if(`d`.`penalizado` is not null,(`d`.`cal7` - `d`.`penalizado`) * 3 * `d`.`grado_dif`,`d`.`cal7` * 3 * `d`.`grado_dif`),NULL) AS `puntaje_7` from ((`softneos_clav`.`planillas` `p` left join `softneos_clav`.`planillad` `d` on(`d`.`planilla` = `p`.`cod_planilla`)) left join `softneos_clav`.`modalidades` `m` on(`m`.`cod_modalidad` = `p`.`modalidad`)) where `m`.`individual` = 1 and `p`.`momento_termino` is not null

